"use client";

import { useState, useEffect } from "react";
import axios from "axios";
import { motion } from "framer-motion";
import { FaHeartbeat, FaUserMd, FaExclamationTriangle, FaMicrophone } from "react-icons/fa";

export default function Diagnose() {

const [mounted,setMounted] = useState(false);
const [symptoms,setSymptoms] = useState("");
const [result,setResult] = useState(null);
const [loading,setLoading] = useState(false);
const [error,setError] = useState("");
const [listening,setListening] = useState(false);

useEffect(()=>{
setMounted(true);
},[]);

const analyze = async () => {

if(!symptoms){
setError("Please describe your symptoms");
return;
}

try{

setLoading(true);
setError("");

const response = await axios.post(
"http://localhost:5000/api/diagnosis",
{symptoms}
);

setResult(response.data);

}catch(err){

console.error(err);
setError("Diagnosis failed");

}

setLoading(false);

};

const startVoiceInput = () => {

if(!mounted) return;

const SpeechRecognition =
window.SpeechRecognition || window.webkitSpeechRecognition;

if(!SpeechRecognition){
alert("Voice recognition not supported in this browser");
return;
}

const recognition = new SpeechRecognition();

recognition.lang = "sw-KE";
recognition.continuous = false;
recognition.interimResults = false;

setListening(true);

recognition.start();

recognition.onresult = (event)=>{

const transcript = event.results[0][0].transcript;

setSymptoms(prev => prev + " " + transcript);

};

recognition.onend = ()=>{
setListening(false);
};

};

const confidence = result ? Math.round(result.confidence * 100) : 0;

const riskLevel =
confidence > 85 ? "High"
: confidence > 60 ? "Medium"
: "Low";

const riskColor =
riskLevel === "High"
? "#ff4757"
: riskLevel === "Medium"
? "#ffa502"
: "#2ed573";

const keywords = symptoms
.split(" ")
.filter(word => word.length > 4);

if(!mounted) return null;

return(

<div style={styles.page}>

<motion.h1
initial={{opacity:0,y:-20}}
animate={{opacity:1,y:0}}
style={styles.title}
>
<FaHeartbeat/> AI Medical Diagnosis
</motion.h1>

<div style={styles.inputCard}>

<textarea
rows="4"
placeholder="Describe your symptoms (example: chest pain, headache, fever)..."
value={symptoms}
onChange={(e)=>setSymptoms(e.target.value)}
style={styles.textarea}
/>

<div style={styles.voiceRow}>

<button
onClick={startVoiceInput}
style={styles.voiceButton}
>

<FaMicrophone/>

{listening ? " Listening..." : " Speak Symptoms"}

</button>

</div>

<motion.button
onClick={analyze}
style={styles.button}
whileHover={{scale:1.05}}
whileTap={{scale:0.95}}
>
{loading ? "Analyzing..." : "Analyze Symptoms"}
</motion.button>

{error && <p style={styles.error}>{error}</p>}

</div>

{loading && (
<motion.div
animate={{rotate:360}}
transition={{repeat:Infinity,duration:1}}
style={styles.loader}
/>
)}

{result && (

<motion.div
initial={{opacity:0}}
animate={{opacity:1}}
style={styles.dashboard}
>

<div style={styles.specialtyCard}>
<h2>Detected Specialty</h2>
<p style={styles.specialty}>{result.specialty}</p>
</div>

<div style={styles.confidenceCard}>

<h3>AI Confidence</h3>

<div style={styles.progressBar}>

<motion.div
style={{
...styles.progressFill,
width:confidence + "%"
}}
initial={{width:0}}
animate={{width:confidence + "%"}}
/>

</div>

<p>{confidence}%</p>

</div>

<div style={{
...styles.riskBox,
background:riskColor
}}>

<FaExclamationTriangle/>

Risk Level: {riskLevel}

</div>

<div style={styles.keywordBox}>

<h3>Detected Symptom Keywords</h3>

{keywords.map((word,i)=>(
<span key={i} style={styles.keyword}>
{word}
</span>
))}

</div>

<h2 style={{marginTop:30}}>Top Doctors</h2>

<div style={styles.doctorGrid}>

{result.doctors.map((doc,index)=>(

<motion.div
key={doc.id}
style={styles.doctorCard}
initial={{opacity:0,y:20}}
animate={{opacity:1,y:0}}
transition={{delay:index * 0.2}}
whileHover={{scale:1.05}}
>

<h3>
<FaUserMd/> {doc.name}
</h3>

<p>{doc.hospital_name}</p>

<p>Experience: {doc.experience} years</p>

<p>Rating ⭐ {doc.rating}</p>

<div style={styles.matchBar}>

<motion.div
style={{
...styles.matchFill,
width:(doc.matchScore || 50) + "%"
}}
/>

</div>

<p>
Match Score {Math.round(doc.matchScore || 0)}%
</p>

</motion.div>

))}

</div>

</motion.div>

)}

</div>

);

}

const styles = {

page:{
minHeight:"100vh",
padding:"40px",
background:"linear-gradient(135deg,#141E30,#243B55)",
fontFamily:"Segoe UI",
color:"white"
},

title:{
textAlign:"center",
marginBottom:"30px"
},

inputCard:{
background:"white",
padding:"25px",
borderRadius:"12px",
maxWidth:"800px",
margin:"0 auto 30px auto",
boxShadow:"0 10px 25px rgba(0,0,0,0.25)"
},

textarea:{
width:"100%",
padding:"15px",
borderRadius:"10px",
border:"1px solid #ddd",
fontSize:"16px",
marginBottom:"10px",
color:"#333",
background:"#fafafa"
},

voiceRow:{
display:"flex",
gap:"10px",
marginBottom:"15px"
},

voiceButton:{
background:"#6c5ce7",
border:"none",
padding:"10px 16px",
borderRadius:"8px",
color:"white",
cursor:"pointer",
fontSize:"14px"
},

button:{
padding:"12px 24px",
borderRadius:"8px",
border:"none",
background:"#0984e3",
color:"white",
fontSize:"16px",
cursor:"pointer"
},

error:{
color:"#ff6b6b"
},

loader:{
width:"50px",
height:"50px",
border:"6px solid white",
borderTop:"6px solid transparent",
borderRadius:"50%",
margin:"30px auto"
},

dashboard:{
marginTop:"30px",
background:"rgba(255,255,255,0.08)",
padding:"25px",
borderRadius:"12px",
backdropFilter:"blur(8px)"
},

specialtyCard:{
marginBottom:"20px"
},

specialty:{
fontSize:"24px",
color:"#f1c40f"
},

confidenceCard:{
marginBottom:"15px"
},

progressBar:{
height:"10px",
background:"rgba(255,255,255,0.2)",
borderRadius:"10px"
},

progressFill:{
height:"100%",
background:"#00ffcc"
},

riskBox:{
padding:"10px",
borderRadius:"8px",
marginTop:"15px",
fontWeight:"bold"
},

keywordBox:{
marginTop:"20px"
},

keyword:{
background:"#00cec9",
padding:"6px 10px",
borderRadius:"6px",
marginRight:"6px",
display:"inline-block",
color:"white"
},

doctorGrid:{
display:"grid",
gridTemplateColumns:"repeat(auto-fit,minmax(250px,1fr))",
gap:"20px",
marginTop:"20px"
},

doctorCard:{
background:"white",
color:"black",
padding:"18px",
borderRadius:"10px"
},

matchBar:{
height:"8px",
background:"#eee",
borderRadius:"5px",
marginTop:"8px"
},

matchFill:{
height:"100%",
background:"#6c5ce7"
}

};